#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long bestPi = -1; long long bestMoves = LLONG_MAX;
        for(int i=0;i<N;i++){
            long long Pi; scanf("%lld", &Pi);
            if(K % Pi == 0){
                long long moves = K / Pi - 1;
                if(moves < bestMoves){
                    bestMoves = moves;
                    bestPi = Pi;
                }
            }
        }
        if(bestPi==-1) printf("-1\n");
        else printf("%lld\n", bestPi);
    }
    return 0;
}

