import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        best_pi = -1
        best_moves = 10**30
        for _ in range(N):
            Pi = int(next(it))
            if K % Pi == 0:
                moves = K // Pi - 1
                if moves < best_moves:
                    best_moves = moves
                    best_pi = Pi
        out_lines.append(str(best_pi if best_pi != -1 else -1))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

